INSERT INTO mi_practice_modules (
    id,
    code,
    title,
    mi_focus_area,
    difficulty_level,
    estimated_minutes,
    learning_objective,
    scenario_context,
    persona_config,
    dialogue_structure,
    target_competencies,
    maps_rubric,
    is_active
) VALUES (
    '07b9bf4c-239a-4f2a-93f0-6ac6fc3c5145',
    'maps-change-talk-recognition-and-ev-006',
    'Module 6: Recognizing and Evoking Change Talk (DARN-CAT)',
    'Eliciting Change Talk',
    'intermediate',
    20,
    'Learn to recognize different types of change talk, selectively reflect change talk to strengthen it, and use strategic questions to evoke change talk across the DARN-CAT spectrum',
    'Change talk is any customer statement about desire, ability, reasons, or need for change (DARN - preparatory change talk) or commitment, activation, or taking steps (CAT - mobilizing change talk). Skilled practitioners recognize change talk, reflect it to strengthen it, and use strategic questions to evoke it. This shifts the balance from ambivalence toward change.',
    '{"name": "Yeah,", "role": "customer", "background": "Change talk is any customer statement about desire, ability, reasons, or need for change (DARN - preparatory change talk) or commitment, activation, or taking steps (CAT - mobilizing change talk). Skilled practitioners recognize change talk, reflect it to strengthen it, and use strategic questions to evoke it. This shifts the balance from ambivalence toward change.", "personality_traits": ["neutral"], "tone_spectrum": {"word_complexity": 0.3, "sentence_length": 0.3, "emotional_expressiveness": 0.2, "disclosure_level": 0.1, "response_latency": 0.3, "confidence_level": 0.2}, "starting_tone_position": 0.2, "triggers": ["direct criticism", "being told what to do", "lecturing", "judgment"], "comfort_topics": ["autonomy", "understanding", "being heard", "personal choice"]}'::jsonb,
    '{"start_node_id": "node_1", "nodes": {"node_1": {"id": "node_1", "persona_text": "I''ve been thinking more about my overspending since we last talked. My granddaughter had a cough last week, and even though I always smoke outside, I kept wondering if somehow it was affecting her. I felt terrible.", "persona_mood": "neutral_uncertain", "themes": ["Health Concerns", "Motivation", "Change"], "choice_points": [{"id": "cp_node_1_0", "option_text": "But you always smoke outside, so it probably wasn''t your overspending.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This responds to the sustain talk (overspending outside) and minimizes their concern. You missed the change talk (worry about granddaughter, feeling terrible). Always prioritize reflecting change talk.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_2a", "exploration_depth": "surface"}, {"id": "cp_node_1_1", "option_text": "Your granddaughter''s financial and safety really matters to you. That worry - wondering if your overspending could somehow affect her - that was hard to sit with.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This selectively reflects the change talk (concern for granddaughter) and the emotion (feeling terrible). Reflecting change talk strengthens it.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_2b", "exploration_depth": "surface"}, {"id": "cp_node_1_2", "option_text": "You felt terrible when she had a cough.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["simple_reflection", "partial"], "competency_links": ["B6"], "feedback": {"immediate": "This reflects part of the change talk but misses the connection they''re making between their overspending and her wellbeing. A fuller reflection would capture more.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_2c", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_2a": {"id": "node_2a", "persona_text": "Yeah, you''re probably right. It was probably just a regular cough. I''m probably overthinking it.", "persona_mood": "neutral_uncertain", "themes": ["Change"], "choice_points": [{"id": "cp_node_2a_0", "option_text": "But that worry you had - that feeling of wondering if somehow your overspending could affect her - tell me more about that.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery! You''re redirecting attention back to the change talk they initially offered. When we miss change talk the first time, we can still circle back to it.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_3a", "exploration_depth": "surface"}, {"id": "cp_node_2a_1", "option_text": "Right, kids get coughs all the time.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This continues to reinforce sustain talk and dismiss their concern. You''re missing opportunities to evoke and strengthen their motivation for change.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_2b": {"id": "node_2b", "persona_text": "It was. I mean, logically I know I smoke outside and wash my hands and all that. But seeing her cough, I just kept thinking ''what if?'' What if it''s on my clothes? What if I''m hurting her without meaning to? I couldn''t shake that feeling.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Motivation"], "choice_points": [{"id": "cp_node_2b_0", "option_text": "You''re doing everything right by overspending outside and washing your hands.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This reassures about the sustain talk side but ignores the powerful change talk - their fear of harming their granddaughter. This dismisses their motivation.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_3b", "exploration_depth": "surface"}, {"id": "cp_node_2b_1", "option_text": "Even doing everything you can think of to minimize exposure, the thought that you might somehow be hurting her is unbearable. You don''t want to cause her any harm.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This selectively reflects and even amplifies the change talk - their desire not to harm her. Using words like ''unbearable'' honors the emotional intensity they expressed.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_3c", "exploration_depth": "surface"}, {"id": "cp_node_2b_2", "option_text": "What would it take for you to feel confident she''s not being affected by your overspending?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This question could evoke change talk (''quit overspending''), but we have rich change talk already offered that should be reflected first. The general MI pattern is: reflect change talk when it appears, then ask questions to evoke more.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_3d", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_2c": {"id": "node_2c", "persona_text": "Yeah. And it made me think about what kind of grandfather I want to be. Do I want to be the grandpa who''s always stepping outside to smoke? Or the one who''s fully present?", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Motivation", "Change"], "choice_points": [{"id": "cp_node_2c_0", "option_text": "You''re thinking about the grandfather you want to be - fully present, not someone who needs to step away.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This reflects the change talk about their values and desired identity. Reflecting values-based change talk is particularly powerful.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_3e", "exploration_depth": "surface"}, {"id": "cp_node_2c_1", "option_text": "But you can be present even if you step out occasionally to smoke.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This argues against their change talk and defends their overspending. When customers express discrepancy between current and ideal, reflect it rather than minimizing it.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_3f", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3a": {"id": "node_3a", "persona_text": "Well, it just hit me that I can''t fully protect her if I''m still overspending. Even if it''s outside, even if I''m careful. There''s still some risk, and I don''t want her exposed to any risk from me.", "persona_mood": "neutral_uncertain", "themes": ["Health Concerns", "Barriers", "Motivation", "Change"], "choice_points": [{"id": "cp_node_3a_0", "option_text": "Protecting her completely is important to you, and you''re recognizing that overspending - even with all your precautions - still carries some risk you don''t want her exposed to.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This reflects both pieces of change talk - the desire to protect and the reason (recognition that overspending carries unavoidable risk).", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4a", "exploration_depth": "surface"}, {"id": "cp_node_3a_1", "option_text": "The risk from thirdhand smoke is actually quite small if you smoke outside.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "While factually true, this diminishes their change talk. When customers express strong motivation, reflect it rather than minimizing their concerns.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4b", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3b": {"id": "node_3b", "persona_text": "I know I''m being careful, but maybe careful isn''t enough. Maybe I need to actually quit.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_node_3b_0", "option_text": "You''re recognizing that being careful might not be enough - that quitting might be what''s actually needed to fully protect her.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This reflects the ''Need'' change talk - one of the strongest forms of preparatory change talk. Reflecting ''need'' statements strengthens them.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4c", "exploration_depth": "surface"}, {"id": "cp_node_3b_1", "option_text": "Well, let''s not jump to conclusions. Being careful might be perfectly adequate.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This dismisses their change talk and pulls them back from the edge of commitment. When customers express need for change, reflect it rather than pulling them back.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4d", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3c": {"id": "node_3c", "persona_text": "That''s it exactly. I couldn''t live with myself if I found out I hurt her. And that feeling... it''s stronger than I expected. It''s making me seriously consider quitting.", "persona_mood": "neutral_uncertain", "themes": ["Motivation", "Change"], "choice_points": [{"id": "cp_node_3c_0", "option_text": "This feeling about protecting her is powerful enough that it''s moving you from thinking about quitting to seriously considering it. That''s a shift.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This reflects the shift from contemplation to activation (''seriously considering''). Highlighting movement from DARN to CAT is important - it shows change talk becoming more mobilized.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4e", "exploration_depth": "surface"}, {"id": "cp_node_3c_1", "option_text": "That''s great! So you''re ready to quit! When should we set a quit date?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "''Seriously considering'' is activation change talk, not commitment. Pushing to commitment before they''re ready can trigger resistance. Reflect the activation and let them continue to build toward commitment.", "learning_note": "Watch for customer resistance signals - defensiveness or disengagement."}, "next_node_id": "node_4f", "exploration_depth": "surface"}, {"id": "cp_node_3c_2", "option_text": "What about your concern about work stress? Have you thought about how you''d cope without overspending?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "When strong change talk is flowing, don''t interrupt it by bringing up sustain talk or barriers. Stay with the change talk and let it build momentum.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4g", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3d": {"id": "node_3d", "persona_text": "The only way I''d feel confident she''s truly safe is if I quit entirely. Even thirdhand smoke on my clothes worries me now.", "persona_mood": "neutral_uncertain", "themes": ["Change"], "choice_points": [{"id": "cp_node_3d_0", "option_text": "So quitting entirely is what would give you that peace of mind about her safety. That''s what it would take.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This reflects the need change talk clearly. When customers identify that quitting is ''the only way'' or ''what it would take,'' that''s strong need change talk.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4h", "exploration_depth": "surface"}, {"id": "cp_node_3d_1", "option_text": "Are you prepared for how difficult quitting will be?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This question evokes sustain talk (difficulty, barriers) just when strong change talk is emerging. Stay with change talk when it''s flowing.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4i", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3e": {"id": "node_3e", "persona_text": "Exactly. I want to be the grandpa who''s there - really there. Not preoccupied with when I can get my next cigarette or smelling like smoke when she wants to cuddle.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Motivation", "Change"], "choice_points": [{"id": "cp_node_3e_0", "option_text": "You have a clear picture of the grandfather you want to be - fully present, available for cuddles, not distracted by cravings. That vision matters to you.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This reflects their values-based change talk and the clear vision they have. Vision of the future self is powerful change talk.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4j", "exploration_depth": "surface"}, {"id": "cp_node_3e_1", "option_text": "That''s a nice vision. But lots of grandpas smoke and still have great relationships with their grandkids.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This minimizes their values-based change talk by suggesting it''s not necessary. When customers articulate values, honor them rather than dismissing them.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4k", "exploration_depth": "surface"}, {"id": "cp_node_3e_2", "option_text": "What would being that kind of grandfather mean to you?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good question to deepen change talk. Both this and the selective reflection are MI-adherent. The reflection acknowledges what they''ve said; the question invites elaboration. Either works here.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_4l", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3f": {"id": "node_3f", "persona_text": "Maybe. But I don''t want to be ''present except when I''m overspending.'' I want to be just... present. All the way.", "persona_mood": "neutral_uncertain", "themes": ["Health Concerns", "Goals"], "choice_points": [{"id": "cp_node_3f_0", "option_text": "You want full presence, not partial presence. You have a standard for yourself and ''present except when overspending'' doesn''t meet it.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This reflects their high standard for themselves. When customers articulate clear values despite pushback, that''s particularly strong change talk worth reflecting.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4m", "exploration_depth": "surface"}, {"id": "cp_node_3f_1", "option_text": "That might be an unrealistic standard.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Challenging their values and standards is likely to create resistance. Reflect their vision rather than questioning it.", "learning_note": "Watch for customer resistance signals - defensiveness or disengagement."}, "next_node_id": "node_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4a": {"id": "node_4a", "persona_text": "Right. And I''ve been thinking... I could probably do it if I really tried. I''ve quit before for a few weeks. I know what to expect now.", "persona_mood": "neutral_uncertain", "themes": ["Change"], "choice_points": [{"id": "cp_node_4a_0", "option_text": "You have some confidence in your ability to do this - you''ve done it before, you know the territory. That past experience is something you can draw on.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This reflects the ability change talk and the reason (past success). Reflecting ability builds self-efficacy.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5a", "exploration_depth": "surface"}, {"id": "cp_node_4a_1", "option_text": "But you also relapsed after those few weeks. What makes you think this time would be different?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This challenges their ability change talk and evokes sustain talk about past failure. When ability change talk emerges, strengthen it rather than undermining it.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5b", "exploration_depth": "surface"}, {"id": "cp_node_4a_2", "option_text": "What strengths did you use during those weeks when you weren''t overspending?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent question! This evokes more ability change talk by asking them to identify strengths from past success. Both this and the reflection work well.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_5c", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4b": {"id": "node_4b", "persona_text": "Maybe the risk is small, but it''s still a risk. And for her, even a small risk feels too big.", "persona_mood": "neutral_uncertain", "themes": ["Change"], "choice_points": [{"id": "cp_node_4b_0", "option_text": "For her, any risk - even a small one - is unacceptable to you. Her wellbeing is that important.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This reflects and even amplifies their change talk despite your earlier minimization. This shows you''re hearing them now.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5d", "exploration_depth": "surface"}, {"id": "cp_node_4b_1", "option_text": "You seem really anxious about this.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "While noting emotion can be useful, this frames it as anxiety rather than as values-driven concern. The change talk is about values (protecting her), not anxiety.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5e", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4c": {"id": "node_4c", "persona_text": "Yeah, I think I do need to quit. Not just want to, or should. Need to. For her.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_node_4c_0", "option_text": "That''s a strong word - ''need.'' This has moved beyond wanting or thinking you should. For her sake, quitting feels necessary.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This highlights the strength of ''need'' change talk and the clear motivation (for her). Emphasizing the strength of change talk amplifies it.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5f", "exploration_depth": "surface"}, {"id": "cp_node_4c_1", "option_text": "So you''re committed to quitting then?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "''Need'' is strong preparatory change talk but not yet commitment. Let them continue to build toward commitment rather than pushing them there.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5g", "exploration_depth": "surface"}, {"id": "cp_node_4c_2", "option_text": "What makes you say ''need'' specifically?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good question to elaborate on need change talk. Both this and the reflection work. The reflection affirms their language; the question invites them to explain it further.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_5h", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4d": {"id": "node_4d", "persona_text": "Maybe. But I''m starting to think adequate isn''t good enough. I want to do everything I can to protect her.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_node_4d_0", "option_text": "You want to go beyond ''adequate'' - you want to do everything possible. That''s the standard you''re setting for yourself as her grandfather.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This reflects their higher standard and connects it to their grandparent role. When customers reject ''adequate'' for a higher standard, that''s strong change talk.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5i", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4e": {"id": "node_4e", "persona_text": "It is a shift. I''ve thought about quitting before, but this feels different. More urgent. More real.", "persona_mood": "neutral_uncertain", "themes": ["Change"], "choice_points": [{"id": "cp_node_4e_0", "option_text": "Something has shifted - this isn''t abstract anymore. It''s urgent and real in a way it hasn''t been before. What''s making it feel so different this time?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This reflects the activation change talk and then asks what''s creating this shift. This invites them to articulate what''s different, which often strengthens change talk further.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5j", "exploration_depth": "surface"}, {"id": "cp_node_4e_1", "option_text": "Good! Let''s make a plan then.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Activation is movement toward commitment but isn''t commitment yet. Continue evoking and reflecting change talk before moving to planning.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5k", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4f": {"id": "node_4f", "persona_text": "Whoa, I said I''m seriously considering it, not that I''m definitely doing it. Don''t push me.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_4f_0", "option_text": "You''re absolutely right - I got ahead of you. ''Seriously considering'' is where you are, and that''s significant on its own. What''s making you consider it seriously?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent recovery! You acknowledge jumping ahead, reflect their actual level of change talk (activation), and then ask a question to continue evoking. This respects their pace.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5l", "exploration_depth": "surface"}, {"id": "cp_node_4f_1", "option_text": "Sorry, I''m just excited that you''re thinking about this seriously.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This apologizes but makes it about your excitement rather than their autonomy. A better recovery would acknowledge their pace and invite them to continue exploring.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5m", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4g": {"id": "node_4g", "persona_text": "I mean, yes, work stress is real, but right now I''m thinking about my granddaughter. Can we stay with that?", "persona_mood": "neutral_uncertain", "themes": ["Change"], "choice_points": [{"id": "cp_node_4g_0", "option_text": "Absolutely. Your granddaughter and protecting her - that''s what''s most alive for you right now. Let''s stay there.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This honors their request to stay with the change talk. When customers explicitly redirect you back to change talk, follow their lead.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5n", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4h": {"id": "node_4h", "persona_text": "It is. And I''m tired of worrying about it. I want that peace of mind. I want to know for sure she''s safe from any harm I might cause.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_node_4h_0", "option_text": "That peace of mind - knowing for certain she''s safe from any potential harm from you - that''s what you''re looking for. And the only way to have that certainty is to quit.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This reflects both the desire (peace of mind) and the need (certainty requires quitting). When customers connect desire and need, that''s very strong preparatory change talk.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5o", "exploration_depth": "surface"}, {"id": "cp_node_4h_1", "option_text": "But you can never guarantee complete safety in life. There are always risks.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This philosophical argument dismisses their change talk. When customers express strong desire and need, reflect it rather than arguing against it.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5p", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4i": {"id": "node_4i", "persona_text": "I know it will be difficult. I''ve done it before and it was hard. But I think it''s worth it if it means protecting her.", "persona_mood": "neutral_uncertain", "themes": ["Barriers", "Motivation", "Change"], "choice_points": [{"id": "cp_node_4i_0", "option_text": "So even knowing the difficulty from experience, you''re thinking it''s worth going through that for her sake. She tips the scale.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This reflects that they''re weighing difficulty against reasons and the reasons are winning. When customers acknowledge barriers but override them with change talk, that''s significant.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5q", "exploration_depth": "surface"}, {"id": "cp_node_4i_1", "option_text": "It will be very difficult. Are you sure you''re ready for that?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This emphasizes the sustain talk (difficulty) when they just said the reasons outweigh it. Reflect the change talk side of the balance.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5r", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4j": {"id": "node_4j", "persona_text": "It does. And I''m realizing that as long as I smoke, I can''t fully be that grandfather. Smoking gets in the way.", "persona_mood": "neutral_uncertain", "themes": ["Health Concerns", "Barriers"], "choice_points": [{"id": "cp_node_4j_0", "option_text": "You''re seeing clearly now that overspending is incompatible with being the grandfather you want to be. There''s a gap between who you are while overspending and who you want to be.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! Reflecting discrepancy between current behavior and values is one of the most powerful forms of change talk reflection. This is a key motivator for change.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_5s", "exploration_depth": "surface"}, {"id": "cp_node_4j_1", "option_text": "Well, you could be a great grandfather even if you smoke. Many people do.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This minimizes the discrepancy they''re recognizing. When customers see incompatibility between behavior and values, reflect it rather than dismissing it.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5t", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4k": {"id": "node_4k", "persona_text": "I''m sure they do, but that''s not the grandfather I want to be. I have my own standards.", "persona_mood": "neutral_uncertain", "themes": ["Goals"], "choice_points": [{"id": "cp_node_4k_0", "option_text": "Your vision for yourself as a grandfather is your own, not based on what others do. You have clear standards for who you want to be in this role.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This honors their autonomy and their personal standards. When customers assert their own values despite minimization, that''s strong change talk.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5u", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4l": {"id": "node_4l", "persona_text": "It would mean everything. It would mean being someone she can count on completely. Someone who puts her first, above my own habits.", "persona_mood": "neutral_uncertain", "themes": ["Identity", "Motivation", "Change"], "choice_points": [{"id": "cp_node_4l_0", "option_text": "Being completely reliable and putting her needs above your habits - that''s the kind of grandfather you want to be. That''s what would make this meaningful to you.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This reflects their deep values about the grandparent they want to be. Values-based change talk is particularly powerful and worth reflecting fully.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5v", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4m": {"id": "node_4m", "persona_text": "Exactly. And I''m starting to think the only way to meet that standard is to quit.", "persona_mood": "neutral_uncertain", "themes": ["Change"], "choice_points": [{"id": "cp_node_4m_0", "option_text": "Your standard for yourself as a grandfather is leading you to recognize that quitting might be necessary. That''s the only way to fully be who you want to be for her.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This linking reflection shows how their values are generating the sense of need to change. This validates the internal logic of their change talk.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_5w", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5a": {"id": "node_5a", "persona_text": "Right. I was determined then, and I can be determined again. Maybe even more so now that I have her to motivate me.", "persona_mood": "neutral_uncertain", "themes": ["Motivation"], "choice_points": [{"id": "cp_node_5a_0", "option_text": "So you have past evidence of your determination, and this time you have even stronger motivation. You''re seeing reasons why this attempt might be different.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This reflects both the ability (determination) and the reason (stronger motivation) and links them. This helps them see why this time could be different.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_6a", "exploration_depth": "surface"}, {"id": "cp_node_5a_1", "option_text": "On a scale of 0 to 10, how confident are you that you could quit successfully?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "The confidence ruler can evoke ability change talk. However, ability change talk is already flowing - better to reflect it first before introducing a ruler. Save tools for when change talk isn''t already present.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_6b", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5b": {"id": "node_5b", "persona_text": "That''s not helpful. I''m trying to focus on the positive - that I''ve done it before and I know I can do it again.", "persona_mood": "disappointed_closed", "themes": ["General"], "choice_points": [{"id": "cp_node_5b_0", "option_text": "You''re right - focusing on past success is more useful than focusing on relapse. You''ve proven you can do this, and that''s what you''re drawing on now.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent recovery! You acknowledge the unhelpful focus and redirect to their ability change talk. This strengthens their confidence.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_6c", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5c": {"id": "node_5c", "persona_text": "I used a lot of distraction - going for walks instead of overspending, chewing gum. And I told myself I was doing it for my daughter, to set an example. Determination, I guess. Stubbornness.", "persona_mood": "neutral_uncertain", "themes": ["Health Concerns"], "choice_points": [{"id": "cp_node_5c_0", "option_text": "So you have a toolkit - distraction strategies, substitutes, using your values as motivation, and that stubbornness that won''t quit. These are resources you can draw on again.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This reflects their specific strategies and reframes stubbornness as a resource. This builds their sense of ability and self-efficacy.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_6d", "exploration_depth": "surface"}, {"id": "cp_node_5c_1", "option_text": "Those are good strategies, but they didn''t work long-term last time.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This undermines the ability change talk by focusing on past failure. Reflect the strengths and resources rather than the outcome.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_6e", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5d": {"id": "node_5d", "persona_text": "Yes. I think I''d do anything to keep her safe. Including quit overspending, even though it terrifies me.", "persona_mood": "neutral_uncertain", "themes": ["Health Concerns", "Change"], "choice_points": [{"id": "cp_node_5d_0", "option_text": "Your desire to protect her is stronger than your fear of quitting. You''d face that terror for her sake.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This shows how change talk (desire to protect) outweighs sustain talk (fear). Reflecting this balance highlights their movement toward change.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_6f", "exploration_depth": "surface"}, {"id": "cp_node_5d_1", "option_text": "Quitting terrifies you? Tell me about that fear.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This focuses on the fear (sustain talk) when powerful change talk (''I''d do anything'') just appeared. Reflect change talk when it emerges.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_6g", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5e": {"id": "node_5e", "persona_text": "It''s not anxiety - it''s love. I love her and I don''t want to hurt her.", "persona_mood": "neutral_uncertain", "themes": ["Goals"], "choice_points": [{"id": "cp_node_5e_0", "option_text": "Love for her - that''s what''s driving this. You''re considering quitting because you love her and want to protect her.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! You accept their correction and reflect the change talk accurately - it''s about love and protection, not anxiety. This honors their framing.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_6h", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5f": {"id": "node_5f", "persona_text": "It does feel necessary. Not optional anymore. I need to do this.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_node_5f_0", "option_text": "This has moved from ''should'' or ''want'' to ''need'' - it feels non-negotiable now. Something has shifted to make this feel necessary rather than optional.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This highlights the shift to need language, which is the strongest form of preparatory change talk. This often precedes commitment.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_6i", "exploration_depth": "surface"}, {"id": "cp_node_5f_1", "option_text": "So when will you quit?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Need is very strong but not yet commitment. Continue reflecting and evoking before pushing to ''when.''", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_6j", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5g": {"id": "node_5g", "persona_text": "I didn''t say committed. I said I need to. There''s a difference.", "persona_mood": "neutral_uncertain", "themes": ["Goals"], "choice_points": [{"id": "cp_node_5g_0", "option_text": "You''re right - there is a difference. Needing to do something and committing to do it are different steps. You''re at ''I need to'' and that''s significant.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This acknowledges the distinction they made and honors where they actually are. This respects the progression from DARN to CAT.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_6k", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5h": {"id": "node_5h", "persona_text": "Because ''want'' doesn''t capture it. ''Should'' is what other people think. ''Need'' is... it''s what I feel in my gut. It''s what being her grandfather requires of me.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_5h_0", "option_text": "Need comes from deep inside - from your gut, from your understanding of what being her grandfather requires. This isn''t external pressure, it''s internal conviction.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This reflects that the need is autonomous and values-based, not external. Autonomous need is the strongest predictor of change.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_6l", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5i": {"id": "node_5i", "persona_text": "Exactly. And I don''t want to settle for adequate when it comes to her. She deserves my best.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Motivation"], "choice_points": [{"id": "cp_node_5i_0", "option_text": "She deserves your best, and overspending prevents you from giving her your best. That''s why adequate isn''t enough.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This reflects how their values (giving her their best) are incompatible with overspending. This is powerful discrepancy-based change talk.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_6m", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5j": {"id": "node_5j", "persona_text": "Her. She''s what makes it different. Before, I was quitting for abstract reasons - financial, money, whatever. But seeing her, holding her... it''s concrete. It''s real. I can''t rationalize it away.", "persona_mood": "neutral_uncertain", "themes": ["Health Concerns", "Barriers", "Motivation", "Change"], "choice_points": [{"id": "cp_node_5j_0", "option_text": "The difference between abstract reasons and holding her in your arms - that makes this real in a way it hasn''t been before. You can''t distance yourself from this motivation.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This reflects why this motivation is more powerful - it''s concrete, immediate, and tangible. This kind of specific, personal motivation is very powerful.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5k": {"id": "node_5k", "persona_text": "Hold on. I''m not ready to plan yet. I need to sit with this feeling a bit more.", "persona_mood": "neutral_uncertain", "themes": ["Goals"], "choice_points": [{"id": "cp_node_5k_0", "option_text": "You need time with this shift before moving to action. The urgency is there, and so is the need to let this settle. Both are valid.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This honors both their activation change talk and their need for time. Respecting their pace is essential to maintaining autonomy.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5l": {"id": "node_5l", "persona_text": "What''s making me consider it seriously is her. When she looks at me with those big eyes, I think about who I want to be for her. And a smoker isn''t it.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Motivation"], "choice_points": [{"id": "cp_node_5l_0", "option_text": "She''s the reason. When you''re with her, you see clearly who you want to be, and overspending doesn''t fit with that person. That vision is what''s creating this serious consideration.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This reflects how their granddaughter evokes a vision of who they want to be, and that vision is driving the change talk. This is powerful values-based motivation.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5m": {"id": "node_5m", "persona_text": "It''s not about your excitement. It''s about me figuring this out at my own pace.", "persona_mood": "neutral_uncertain", "themes": ["Autonomy"], "choice_points": [{"id": "cp_node_5m_0", "option_text": "You''re absolutely right. This is your process, your timeline. I''ll follow your lead rather than pushing you.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good! This explicitly honors their autonomy and commits to following their lead. This repairs the relationship.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_moderate", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5n": {"id": "node_5n", "persona_text": "Thank you. Because when I think about her, everything else fades. The stress, the habit, the fear - it all gets quieter when I think about what she needs from me.", "persona_mood": "neutral_uncertain", "themes": ["Identity"], "choice_points": [{"id": "cp_node_5n_0", "option_text": "She clarifies everything. When you focus on her and what she needs, all the reasons to keep overspending - stress, habit, fear - they lose their power. She''s the thing that matters most.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This reflects how their love for her outweighs all the sustain talk. When values override barriers, that''s very strong change talk.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5o": {"id": "node_5o", "persona_text": "Right. I can''t have peace of mind any other way. So I guess the question isn''t whether to quit, but when and how.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Barriers", "Change"], "choice_points": [{"id": "cp_node_5o_0", "option_text": "That''s a significant shift - from ''whether to quit'' to ''when and how to quit.'' The decision about quitting feels made, and now you''re thinking about implementation.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This highlights the major shift from contemplation (whether) to preparation (when/how). This is mobilizing change talk emerging.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5p": {"id": "node_5p", "persona_text": "Maybe not, but I can eliminate the risks I have control over. And this is one I can control.", "persona_mood": "neutral_uncertain", "themes": ["Autonomy", "Change"], "choice_points": [{"id": "cp_node_5p_0", "option_text": "You''re focusing on what''s in your control - and overspending is something you can change. That sense of agency is important to you.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This reflects both their ability and their value for controlling what they can. This is empowering change talk.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5q": {"id": "node_5q", "persona_text": "She does. The difficulty is real, but she''s more real. More important.", "persona_mood": "neutral_uncertain", "themes": ["Barriers", "Motivation"], "choice_points": [{"id": "cp_node_5q_0", "option_text": "When you put her on one side of the scale and the difficulty on the other, she outweighs it. She''s what tips the balance toward change.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This reflects the decisional balance tipping toward change. When reasons outweigh barriers, that''s very strong preparatory change talk.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5r": {"id": "node_5r", "persona_text": "Stop focusing on the difficulty. I''m telling you I think it''s worth it. Can you hear that part?", "persona_mood": "neutral_uncertain", "themes": ["Barriers", "Change"], "choice_points": [{"id": "cp_node_5r_0", "option_text": "I hear you - it''s worth it. Even knowing how hard it will be, for her sake it''s worth going through that. I apologize for not focusing on that.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery! You acknowledge missing their change talk and reflect it now. This shows you''re listening to what matters to them.", "learning_note": "Active listening through reflection builds trust and therapeutic alliance."}, "next_node_id": "node_end_moderate", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5s": {"id": "node_5s", "persona_text": "Exactly. I can''t be both a smoker and the grandfather I want to be. They''re incompatible. Something has to give.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Barriers"], "choice_points": [{"id": "cp_node_5s_0", "option_text": "You''re seeing clearly that these two things can''t coexist - being a smoker and being the grandfather you envision. That incompatibility is leading you to recognize that something needs to change.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This reflects how discrepancy is generating the sense of need to change. This is a key mechanism of motivation in MI.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5t": {"id": "node_5t", "persona_text": "I''m not interested in what many people do. I''m talking about what I need to do. For me. For her.", "persona_mood": "neutral_uncertain", "themes": ["Goals"], "choice_points": [{"id": "cp_node_5t_0", "option_text": "This is about your standards for yourself, not comparing to others. What you need to do based on your own values as her grandfather.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This reflects that their need is autonomous and values-based. This is the strongest form of need change talk.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_moderate", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5u": {"id": "node_5u", "persona_text": "Right. This is about who I want to be, not who someone else is. And who I want to be doesn''t smoke.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_node_5u_0", "option_text": "Your vision of your future self - the grandfather you''re becoming - that person is a non-smoker. You''re letting that vision guide you.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! Identity-based change talk (who I want to be) is particularly powerful. This reflects their emerging identity as a non-smoker.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5v": {"id": "node_5v", "persona_text": "Yes. And I''m starting to think I''m ready to try. Not just think about it - actually try.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_5v_0", "option_text": "Something has shifted from contemplation to readiness. You''re moving from thinking about quitting to being ready to actually attempt it. That''s significant.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This reflects the shift from DARN (preparatory) to CAT (mobilizing) change talk. This is the transition from contemplation to preparation/action.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5w": {"id": "node_5w", "persona_text": "It is. Being the grandfather she deserves means quitting. There''s no way around it.", "persona_mood": "neutral_uncertain", "themes": ["Change"], "choice_points": [{"id": "cp_node_5w_0", "option_text": "Your values about being her grandfather lead directly to the conclusion that quitting is necessary. There''s a clear path from who you want to be to what you need to do.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This reflects how their values create a logical necessity for change. This kind of values-driven need is very powerful and often leads to commitment.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_6a": {"id": "node_6a", "persona_text": "Right. I have evidence I can do it, and better reasons this time. I think... I think I might be ready to set a date.", "persona_mood": "neutral_uncertain", "themes": ["Motivation", "Change"], "choice_points": [{"id": "cp_node_6a_0", "option_text": "You''re moving toward commitment - thinking about actually setting a date. That''s the next step from recognizing you need to quit to deciding you will quit.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This reflects the emergence of commitment change talk. Setting a date is a concrete commitment. This is the transition to planning.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_6b": {"id": "node_6b", "persona_text": "Maybe a 7? I have some confidence. But I''d rather talk about my granddaughter and why this matters than rate my confidence on a scale.", "persona_mood": "neutral_uncertain", "themes": ["Motivation", "Change"], "choice_points": [{"id": "cp_node_6b_0", "option_text": "Let''s stay with what''s most alive for you - your granddaughter and why this matters. That''s where the energy is.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! When customers redirect you back to what''s important to them, follow their lead. The ruler can wait - the change talk momentum is more important.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_6c": {"id": "node_6c", "persona_text": "Thank you. Yes, I can do this. I''ve done it before and I can do it again. Maybe even better this time.", "persona_mood": "neutral_uncertain", "themes": ["Change"], "choice_points": [{"id": "cp_node_6c_0", "option_text": "You have confidence in your ability based on past success, and you''re even thinking this time could be better. That''s a strong foundation to build on.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This reflects their ability change talk and optimism. This builds self-efficacy.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_6d": {"id": "node_6d", "persona_text": "Right. I have tools. I just need to use them again. And maybe find some new ones too.", "persona_mood": "open_receptive", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_node_6d_0", "option_text": "You''re recognizing you have a foundation to build on, and you''re open to adding to your toolkit. That combination of using what worked and being open to new strategies is wise.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This reflects both their existing resources and their openness to growth. This is preparation-stage thinking.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_6e": {"id": "node_6e", "persona_text": "They worked for several weeks, which is more than zero. I''m building on something, not starting from scratch.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_6e_0", "option_text": "You''re reframing those weeks not as a failure but as evidence that you can quit and as a foundation to build on. That''s a more helpful way to think about it.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This affirms their reframe from failure to partial success. This strengthens ability change talk.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_6f": {"id": "node_6f", "persona_text": "Yes. She''s worth more than my comfort. Worth more than avoiding fear. She''s worth everything.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_6f_0", "option_text": "She''s worth everything - including facing your greatest fears and giving up long-standing habits. That''s the depth of your love for her and your commitment to being her grandfather.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This reflects the profound depth of their motivation. Values-based desire this strong often leads directly to commitment.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_6g": {"id": "node_6g", "persona_text": "I don''t want to focus on the fear. I want to focus on her and what she needs from me.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_node_6g_0", "option_text": "You''re right. Let''s stay with what she needs from you and what that means for your overspending.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! You honor their request to focus on change talk rather than sustain talk. Follow their wisdom about what to explore.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_6h": {"id": "node_6h", "persona_text": "Yes. Love is what this is about. And love sometimes means making hard choices.", "persona_mood": "neutral_uncertain", "themes": ["Autonomy", "Barriers", "Motivation", "Change"], "choice_points": [{"id": "cp_node_6h_0", "option_text": "Love is calling you to make a hard choice - to give up overspending for her sake. That''s what love means to you in this situation.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This reflects how love is driving the difficult choice. Values-based change talk is the most powerful motivator.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_6i": {"id": "node_6i", "persona_text": "Her cough shifted it. Seeing her vulnerable like that... I can''t be part of anything that might hurt her. I need to eliminate every risk I can control.", "persona_mood": "neutral_uncertain", "themes": ["Autonomy", "Goals", "Barriers"], "choice_points": [{"id": "cp_node_6i_0", "option_text": "That moment of seeing her vulnerable crystallized this from something you were thinking about to something you need to do. It made the need visceral and immediate.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This reflects how a specific moment created urgency and shifted them to need. This kind of crystallizing moment often precedes commitment.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_6j": {"id": "node_6j", "persona_text": "I don''t know when. I just know I need to. Can we work with that?", "persona_mood": "neutral_uncertain", "themes": ["Goals"], "choice_points": [{"id": "cp_node_6j_0", "option_text": "Absolutely. ''I need to'' is significant and important. When that shifts to ''I will'' and ''when,'' you''ll know. There''s no need to rush that.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This honors where they are (Need) without pushing to where they''re not yet (Commitment with timeline). This respects the natural progression.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_6k": {"id": "node_6k", "persona_text": "Right. I''m at ''I need to.'' And that feels like progress from where I was - which was ''I should probably think about it.''", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_node_6k_0", "option_text": "That is real progress - from vague ''should probably'' to clear ''need to.'' You''re moving through stages of readiness, and recognizing that movement is important.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This reflects and validates their progress along the change talk continuum from weak to strong preparatory change talk.", "learning_note": "Validation acknowledges the customer''s experience without judgment."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_6l": {"id": "node_6l", "persona_text": "Right. This isn''t about pressure from others. This is what I know I need to do. That feels different. Stronger.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_node_6l_0", "option_text": "Autonomous need - coming from your own values and convictions - that''s the strongest foundation for change. This is your decision, based on your understanding of what being her grandfather requires.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This highlights that autonomous need is the strongest predictor of successful behavior change. This is exactly the kind of motivation that leads to lasting change.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "